#!/usr/bin/env tsx
/**
 * File Search StoreとManifestを同期
 */

import fs from 'fs';
import path from 'path';

const MANIFEST_PATH = path.join(process.cwd(), 'data/file-store-manifest.json');

interface ManifestFile {
  file_id: string;
  file_search_store_name?: string;
  display_name: string;
  source_type: 'qa' | 'web';
  uploaded_at: string;
  locale?: string;
  category?: string;
  url?: string;
}

interface Manifest {
  version: string;
  updated_at: string;
  file_search_store_name?: string;
  files: ManifestFile[];
}

// デフォルトのStore名（manifest.jsonの既存値）
const DEFAULT_STORE_NAME = 'fileSearchStores/wmg2027aichatbotstore-wea54ebrqi39';
const DEFAULT_STORE_DISPLAY_NAME = 'wmg2027-ai-chatbot-store';

async function syncManifest() {
  const apiKey = process.env.GEMINI_API_KEY;
  if (!apiKey) {
    console.error('GEMINI_API_KEY not set');
    process.exit(1);
  }

  // 環境変数でStore名を上書き可能
  const envStoreName = process.env.FILE_SEARCH_STORE_NAME;
  let storeName = '';

  if (envStoreName && envStoreName.startsWith('fileSearchStores/')) {
    // フルパスが指定されている場合は直接使用
    storeName = envStoreName;
    console.log(`環境変数で指定されたFile Search Storeを使用: ${storeName}\n`);
  } else {
    // 指定がない場合はデフォルト値を使用
    storeName = DEFAULT_STORE_NAME;
    console.log(`デフォルトのFile Search Storeを使用: ${storeName}\n`);
  }

  console.log('Fetching documents from File Search Store...\n');

  // 全ドキュメントを取得
  let pageToken: string | undefined;
  let allDocs: any[] = [];

  do {
    const url = `https://generativelanguage.googleapis.com/v1beta/${storeName}/documents?key=${apiKey}&pageSize=20${pageToken ? `&pageToken=${pageToken}` : ''}`;
    const resp = await fetch(url);
    const data = await resp.json();

    if (data.documents) {
      allDocs = allDocs.concat(data.documents);
    }
    pageToken = data.nextPageToken;
  } while (pageToken);

  console.log(`Found ${allDocs.length} documents\n`);

  // Manifestを構築
  const files: ManifestFile[] = allDocs.map(doc => {
    const sourceType =
      doc.customMetadata?.find((m: any) => m.key === 'source_type')?.stringValue || 'web';
    const locale = doc.customMetadata?.find((m: any) => m.key === 'locale')?.stringValue;
    const category = doc.customMetadata?.find((m: any) => m.key === 'category')?.stringValue;
    const url = doc.customMetadata?.find((m: any) => m.key === 'url')?.stringValue;

    return {
      file_id: doc.name,
      file_search_store_name: storeName,
      display_name: doc.displayName,
      source_type: sourceType as 'qa' | 'web',
      uploaded_at: doc.createTime,
      locale: locale,
      category: category,
      ...(url ? { url } : {}),
    };
  });

  const manifest: Manifest = {
    version: '3.0.0',
    updated_at: new Date().toISOString(),
    file_search_store_name: storeName,
    files: files,
  };

  // 統計
  const webCount = files.filter(f => f.source_type === 'web').length;
  const qaCount = files.filter(f => f.source_type === 'qa').length;

  console.log(`Web documents: ${webCount}`);
  console.log(`QA documents: ${qaCount}`);
  console.log(`Total: ${files.length}\n`);

  // 保存
  fs.writeFileSync(MANIFEST_PATH, JSON.stringify(manifest, null, 2));
  console.log(`Manifest saved to: ${MANIFEST_PATH}`);
}

syncManifest().catch(console.error);

