#!/usr/bin/env tsx
/**
 * Generic File Upload CLI
 * 汎用ファイルアップロードスクリプト
 *
 * 使用方法:
 * pnpm upload:file <file-path> [options]
 *
 * オプション:
 *   --category <category>  カテゴリ名（デフォルト: ファイル名から推測）
 *   --locale <locale>      ロケール（デフォルト: ja）
 *   --type <type>          ソースタイプ: qa | web（デフォルト: qa）
 *
 * 対応フォーマット:
 *   - テキスト: .txt, .md, .json, .csv
 *   - ドキュメント: .pdf, .docx, .xlsx
 *   - その他: 任意のテキストファイル
 */

import fs from 'fs';
import path from 'path';
import { uploadToFileStore, updateManifest, type ManifestFile } from './lib/file-uploader';

const MANIFEST_PATH = path.join(process.cwd(), 'data/file-store-manifest.json');

interface UploadOptions {
  filePath: string;
  category?: string;
  locale: string;
  sourceType: 'qa' | 'web';
}

function parseArgs(): UploadOptions | null {
  const args = process.argv.slice(2);

  if (args.length === 0 || args[0] === '--help' || args[0] === '-h') {
    console.log(`
📤 汎用ファイルアップロードスクリプト

使用方法:
  pnpm upload:file <file-path> [options]

オプション:
  --category <category>  カテゴリ名（デフォルト: ファイル名から推測）
  --locale <locale>      ロケール（デフォルト: ja）
  --type <type>          ソースタイプ: qa | web（デフォルト: qa）

対応フォーマット:
  - テキスト: .txt, .md, .json, .csv
  - Excel: .xlsx, .xls
  - PDF: .pdf（テキスト抽出）
  - その他: 任意のテキストファイル

例:
  pnpm upload:file ./data/faq.txt --category FAQ --locale ja
  pnpm upload:file ./docs/manual.md --type qa
  pnpm upload:file ./data/questions.xlsx --category お問い合わせ
`);
    return null;
  }

  const filePath = args[0];
  let category: string | undefined;
  let locale = 'ja';
  let sourceType: 'qa' | 'web' = 'qa';

  for (let i = 1; i < args.length; i++) {
    switch (args[i]) {
      case '--category':
        category = args[++i];
        break;
      case '--locale':
        locale = args[++i];
        break;
      case '--type':
        const type = args[++i];
        if (type === 'qa' || type === 'web') {
          sourceType = type;
        }
        break;
    }
  }

  return { filePath, category, locale, sourceType };
}

/**
 * ファイル内容を読み込む
 */
async function readFileContent(filePath: string): Promise<string> {
  const ext = path.extname(filePath).toLowerCase();

  // テキストベースのファイル
  if (['.txt', '.md', '.json', '.csv', '.tsv', '.xml', '.html'].includes(ext)) {
    return fs.readFileSync(filePath, 'utf-8');
  }

  // Excel ファイル
  if (['.xlsx', '.xls'].includes(ext)) {
    const xlsx = await import('xlsx');
    const xlsxModule = xlsx.default || xlsx;
    const workbook = xlsxModule.readFile(filePath);
    let content = '';

    // 全シートをテキストに変換
    for (const sheetName of workbook.SheetNames) {
      const sheet = workbook.Sheets[sheetName];
      content += `## ${sheetName}\n\n`;
      content += xlsxModule.utils.sheet_to_csv(sheet);
      content += '\n\n';
    }

    return content;
  }

  // PDF ファイル（Node.jsでの基本的なPDF処理は限定的）
  if (ext === '.pdf') {
    console.warn('⚠️  PDF形式: テキスト抽出は限定的です。テキストファイルへの変換を推奨します。');
    // 基本的なバイナリ読み込み（File Search StoreがPDF対応している場合）
    return fs.readFileSync(filePath, 'utf-8');
  }

  // その他のファイルはテキストとして読み込み
  return fs.readFileSync(filePath, 'utf-8');
}

async function main() {
  const options = parseArgs();
  if (!options) {
    process.exit(0);
  }

  const apiKey = process.env.GEMINI_API_KEY;
  if (!apiKey) {
    console.error('❌ エラー: GEMINI_API_KEY環境変数が設定されていません');
    process.exit(1);
  }

  const { filePath, category, locale, sourceType } = options;

  // ファイル存在確認
  const absolutePath = path.isAbsolute(filePath) ? filePath : path.join(process.cwd(), filePath);

  if (!fs.existsSync(absolutePath)) {
    console.error(`❌ エラー: ファイルが見つかりません: ${absolutePath}`);
    process.exit(1);
  }

  const fileName = path.basename(absolutePath);
  const displayName = `${sourceType}-${fileName}`;
  const finalCategory = category || path.basename(fileName, path.extname(fileName));

  console.log('🚀 ファイルアップロード開始\n');
  console.log(`📄 ファイル: ${fileName}`);
  console.log(`   カテゴリ: ${finalCategory}`);
  console.log(`   ロケール: ${locale}`);
  console.log(`   タイプ: ${sourceType}\n`);

  // ファイル読み込み
  console.log('  - ファイル読み込み中...');
  let content: string;
  try {
    content = await readFileContent(absolutePath);
    console.log(`  ✓ 読み込み完了（${content.length}文字）`);
  } catch (error) {
    console.error(`  ❌ ファイル読み込みエラー: ${error}`);
    process.exit(1);
  }

  // Gemini File Search Storeへアップロード
  console.log('  - Gemini File Search Storeへアップロード中...');
  const uploadResult = await uploadToFileStore(apiKey, content, {
    display_name: displayName,
    source_type: sourceType,
    locale: locale,
    category: finalCategory,
  });

  if (!uploadResult.success) {
    console.error(`  ❌ アップロードエラー: ${uploadResult.error}`);
    process.exit(1);
  }

  console.log(`  ✓ アップロード完了: ${uploadResult.file_id}`);

  // Manifest更新
  const manifestFile: ManifestFile = {
    file_id: uploadResult.file_id!,
    file_search_store_name: uploadResult.file_search_store_name,
    display_name: displayName,
    source_type: sourceType,
    uploaded_at: new Date().toISOString(),
    locale: locale,
    category: finalCategory,
  };

  updateManifest(MANIFEST_PATH, manifestFile);
  console.log('  ✓ Manifest更新完了\n');

  console.log('✅ ファイルアップロードが完了しました');
  console.log(`   File ID: ${uploadResult.file_id}`);
  console.log(`   Store: ${uploadResult.file_search_store_name}`);
}

main().catch(error => {
  console.error('❌ 予期しないエラー:', error);
  process.exit(1);
});

content.thinking:
Now I understand the full picture:

1. **upload-file.ts**: When uploading PDFs, there's a warning at line 118-121:
   ```typescript
   if (ext === '.pdf') {
     console.warn('⚠️  PDF形式: テキスト抽出は限定的です。テキストファイルへの変換を推奨します。');
     // 基本的なバイナリ読み込み（File Search StoreがPDF対応している場合）
     return fs.readFileSync(filePath, 'utf-8');
   }
   ```

   This is reading a PDF as UTF-8 text, which is WRONG! PDFs are binary files and cannot be read as UTF-8 text. This would result in corrupted content being uploaded.

2. **The real issue**: The `upload-file.ts` script does NOT properly handle PDF files. It tries to read them as UTF-8 text, which will not work.

3. **Two potential issues**:
   - **Manifest out of sync**: Even if PDFs were uploaded directly to the File Search Store via Gemini Console, they wouldn't appear in the manifest because the manifest is updated by the upload scripts
   - **PDF content not extracted**: If PDFs were uploaded using this script, the content would be corrupted because it's being read as UTF-8 text instead of properly processed

Let me check how Gemini's File Search Store handles PDFs natively. The script's `uploadToFileStore` function might be uploading the file directly to Gemini, and Gemini itself should handle PDF parsing.

