    60→
    61→  // JSONエラーレスポンスをパース
    62→  try {
    63→    const jsonMatch = errorStr.match(/\{[\s\S]*\}/);
    64→    if (jsonMatch) {
    65→      const errorObj = JSON.parse(jsonMatch[0]);
    66→      const code = errorObj.error?.code || errorObj.code;
    67→      const status = errorObj.error?.status || errorObj.status;
    68→      const message = errorObj.error?.message || errorObj.message;
    69→
    70→      // HTTPステータスコードに基づくメッセージ
    71→      switch (code) {
    72→        case 400:
    73→          return `リクエストエラー: ${message || 'ファイル形式またはサイズが不正です'}`;
    74→        case 401:
    75→          return 'API認証エラー: APIキーが無効または期限切れです';
    76→        case 403:
    77→          return 'アクセス拒否: このファイルまたはリソースへのアクセス権限がありません';
    78→        case 404:
    79→          return 'リソース未検出: 指定されたファイルまたはストアが見つかりません';
    80→        case 429:
    81→          return 'レート制限: APIリクエスト数の上限に達しました。しばらく待ってから再試行してください';
    82→        case 500:
    83→          return 'サーバー内部エラー: Gemini APIサーバーで問題が発生しました';
    84→        case 503:
    85→          return 'サービス一時停止: Gemini APIサーバーが一時的に利用できません。しばらく待ってから再試行してください';
    86→        default:
    87→          if (status) {
    88→            return `${status} (${code}): ${message || 'APIエラーが発生しました'}`;
    89→          }
    90→      }
    91→    }
    92→  } catch {
    93→    // JSONパース失敗時は元のメッセージを使用
    94→  }
    95→
    96→  // 一般的なエラーパターン
    97→  if (errorStr.includes('ENOTFOUND') || errorStr.includes('ECONNREFUSED')) {
    98→    return 'ネットワークエラー: Gemini APIサーバーに接続できません';
    99→  }
   100→  if (errorStr.includes('timeout') || errorStr.includes('ETIMEDOUT')) {
