   118→    // フルパスからdisplayNameを推測（末尾のIDを除去）
   119→    // 例: fileSearchStores/wmg2027-prod-xxx → wmg2027-prod-xxx は不明なので
   120→    // 環境変数指定時は直接そのStoreを使用する
   121→    console.log(`  📌 環境変数からStore名を使用: ${envStoreName}`);
   122→    return envStoreName;
   123→  }
   124→  return DEFAULT_STORE_DISPLAY_NAME;
   125→}
   126→
   127→/**
   128→ * File Search Storeを取得または作成（新SDK使用）
   129→ *
   130→ * 環境分離:
   131→ * - FILE_SEARCH_STORE_NAME 環境変数でフルパスを指定可能
   132→ * - 未設定時は DEFAULT_STORE_DISPLAY_NAME で検索/作成
   133→ */
   134→async function getOrCreateFileSearchStore(ai: GoogleGenAI, storeName?: string): Promise<string> {
   135→  // キャッシュがあれば返す
   136→  if (cachedStoreName) {
   137→    console.log(`  ✓ キャッシュ済みFile Search Storeを使用: ${cachedStoreName}`);
   138→    return cachedStoreName;
   139→  }
   140→
   141→  // 環境変数でフルパスが指定されている場合は直接使用
   142→  const envStoreName = process.env.FILE_SEARCH_STORE_NAME;
   143→  if (envStoreName && envStoreName.startsWith('fileSearchStores/')) {
   144→    console.log(`  ✓ 環境変数で指定されたFile Search Storeを使用: ${envStoreName}`);
   145→    cachedStoreName = envStoreName;
   146→    return envStoreName;
   147→  }
   148→
   149→  // Store表示名を決定
   150→  const displayName = storeName || getStoreDisplayName();
   151→
   152→  try {
   153→    // 既存のストアを検索
   154→    console.log('  📋 既存のFile Search Storeを検索中...');
   155→    const stores = await ai.fileSearchStores.list();
   156→
   157→    for await (const store of stores) {
   158→      if (store.displayName === displayName) {
   159→        console.log(`  ✓ 既存のFile Search Storeを発見: ${store.name}`);
   160→        cachedStoreName = store.name || null;
   161→        return store.name!;
   162→      }
   163→    }
   164→
   165→    // 新規作成
   166→    console.log(`  🆕 新しいFile Search Storeを作成中: ${displayName}`);
   167→    const newStore = await ai.fileSearchStores.create({
   168→      config: { displayName: displayName },
   169→    });
   170→
   171→    console.log(`  ✓ File Search Store作成完了: ${newStore.name}`);
   172→    cachedStoreName = newStore.name || null;
   173→    return newStore.name!;
   174→  } catch (error) {
   175→    throw new Error(
   176→      `File Search Store creation failed: ${error instanceof Error ? error.message : 'Unknown error'}`
   177→    );
   178→  }
   179→}
   180→
   181→/**
   182→ * File Search Storeにファイルをアップロード（新SDK使用）
   183→ *
   184→ * 重要: File Search Storeは永続化されるため、48時間制限なし
   185→ */
   186→export async function uploadToFileStore(
   187→  apiKey: string,
   188→  jsonContent: any,
   189→  metadata: FileMetadata
   190→): Promise<UploadResult> {
   191→  try {
   192→    // 新SDKでGoogleGenAIクライアントを作成
   193→    const ai = new GoogleGenAI({ apiKey });
   194→
   195→    // File Search Storeを取得または作成
   196→    const fileSearchStoreName = await getOrCreateFileSearchStore(ai);
   197→
   198→    // 一時ファイルを作成（Vercelでは/tmpのみ書き込み可能）
   199→    const isVercel = process.env.VERCEL === '1';
   200→    const tempDir = isVercel ? '/tmp' : path.join(process.cwd(), 'temp');
   201→    if (!isVercel && !fs.existsSync(tempDir)) {
   202→      fs.mkdirSync(tempDir, { recursive: true });
   203→    }
   204→
   205→    const tempFilePath = path.join(tempDir, `${Date.now()}.txt`);
   206→
   207→    // コンテンツをテキスト形式で保存
   208→    const content =
   209→      typeof jsonContent === 'string'
   210→        ? jsonContent
   211→        : typeof jsonContent === 'object' && jsonContent.content
   212→          ? jsonContent.content
   213→          : JSON.stringify(jsonContent, null, 2);
   214→    fs.writeFileSync(tempFilePath, content);
   215→
   216→    console.log(`  📤 ファイルをアップロード中: ${metadata.display_name}`);
   217→
   218→    // File Search Store Upload API（新SDK）
   219→    const operation = await ai.fileSearchStores.uploadToFileSearchStore({
   220→      file: tempFilePath,
   221→      fileSearchStoreName: fileSearchStoreName,
   222→      config: {
   223→        displayName: metadata.display_name,
   224→        customMetadata: [
   225→          { key: 'source_type', stringValue: metadata.source_type },
   226→          ...(metadata.locale ? [{ key: 'locale', stringValue: metadata.locale }] : []),
   227→          ...(metadata.category ? [{ key: 'category', stringValue: metadata.category }] : []),
   228→          ...(metadata.url ? [{ key: 'url', stringValue: metadata.url }] : []),
   229→        ],
   230→      },
   231→    });
   232→
   233→    // 一時ファイルを削除
   234→    fs.unlinkSync(tempFilePath);
   235→
   236→    // オペレーション完了を待つ
   237→    let result = operation;
   238→    while (!result.done) {
   239→      console.log('    ⏳ アップロード処理中...');
   240→      await new Promise(resolve => setTimeout(resolve, 2000));
   241→
   242→      // オペレーションの状態を確認（公式ドキュメント準拠: { operation: result }）
   243→      result = await ai.operations.get({ operation: result });
   244→    }
   245→
   246→    if (result.error) {
   247→      throw new Error(`Upload operation failed: ${JSON.stringify(result.error)}`);
   248→    }
   249→
   250→    // レスポンスからファイル情報を取得
   251→    // File Search Store APIは documentName を返す（nameではない）
   252→    const fileData = result.response as any;
   253→    const documentName = fileData?.documentName || fileData?.name;
   254→
   255→    console.log(`  ✅ アップロード完了: ${metadata.display_name} (${documentName})`);
   256→
   257→    return {
   258→      success: true,
   259→      file_id: documentName || `uploaded-${Date.now()}`,
   260→      file_search_store_name: fileSearchStoreName,
   261→      display_name: metadata.display_name,
   262→      mime_type: 'text/plain',
   263→    };
   264→  } catch (error) {
   265→    const formattedError = formatApiError(error);
   266→    console.error(`  ❌ アップロード失敗: ${metadata.display_name}`);
   267→    console.error(`     エラー: ${formattedError}`);
   268→    return {
   269→      success: false,
   270→      error: formattedError,
   271→    };
   272→  }
   273→}
   274→
   275→/**
   276→ * manifestファイルを更新
   277→ */
   278→export function updateManifest(manifestPath: string, newFile: ManifestFile): void {
   279→  let manifest: Manifest;
   280→
   281→  if (fs.existsSync(manifestPath)) {
   282→    manifest = JSON.parse(fs.readFileSync(manifestPath, 'utf-8'));
   283→  } else {
   284→    manifest = {
   285→      version: '3.0.0', // File Search Store（新SDK）対応バージョン
   286→      updated_at: '',
   287→      files: [],
   288→    };
   289→  }
   290→
   291→  // File Search Store名を保持
   292→  if (newFile.file_search_store_name && !manifest.file_search_store_name) {
   293→    manifest.file_search_store_name = newFile.file_search_store_name;
   294→  }
   295→
   296→  // 既存のファイルを除外（同じdisplay_nameの場合は上書き）
   297→  manifest.files = manifest.files.filter(f => f.display_name !== newFile.display_name);
   298→
   299→  manifest.files.push(newFile);
   300→  manifest.updated_at = new Date().toISOString();
   301→  manifest.version = '3.0.0'; // バージョン更新
   302→
   303→  fs.writeFileSync(manifestPath, JSON.stringify(manifest, null, 2));
   304→}
   305→
   306→/**
   307→ * File Search Store内のドキュメントを削除
   308→ * Store Documents API使用（Files APIではなく）
   309→ *
   310→ * 注意: force=true パラメータを使用して非空ドキュメントも削除可能
   311→ */
   312→export async function deleteFromFileStore(apiKey: string, documentName: string): Promise<boolean> {
   313→  try {
   314→    // documentNameの形式: fileSearchStores/{store}/documents/{doc}
   315→    const baseUrl = documentName.startsWith('fileSearchStores/')
   316→      ? `https://generativelanguage.googleapis.com/v1beta/${documentName}`
   317→      : `https://generativelanguage.googleapis.com/v1beta/${documentName}`;
   318→
   319→    // force=true を追加して非空ドキュメントも削除可能に
   320→    const url = `${baseUrl}?force=true`;
   321→
   322→    const response = await fetch(url, {
   323→      method: 'DELETE',
   324→      headers: {
   325→        'x-goog-api-key': apiKey,
   326→      },
   327→    });
   328→
   329→    if (response.ok) {
   330→      console.log(`  🗑️ ドキュメント削除完了: ${documentName}`);
   331→      return true;
   332→    } else {
   333→      const error = await response.json();
   334→      console.error(`  ❌ ドキュメント削除失敗: ${documentName}`, error);
   335→      return false;
   336→    }
   337→  } catch (error) {
   338→    console.error(`  ❌ ドキュメント削除失敗: ${documentName}`, error);
   339→    return false;
   340→  }
   341→}
   342→
   343→/**
   344→ * File Search Store内のドキュメント一覧を取得
   345→ * Store Documents API使用（Files APIではなく）
   346→ */
   347→export async function listFilesInStore(
   348→  apiKey: string,
   349→  fileSearchStoreName: string
   350→): Promise<any[]> {
   351→  try {
   352→    // fileSearchStoreName形式: fileSearchStores/{storeName}
   353→    const storeName = fileSearchStoreName.replace('fileSearchStores/', '');
   354→    const allDocuments: any[] = [];
   355→    let pageToken: string | undefined;
   356→
   357→    do {
   358→      const url = new URL(
   359→        `https://generativelanguage.googleapis.com/v1beta/fileSearchStores/${storeName}/documents`
   360→      );
   361→      url.searchParams.set('pageSize', '20'); // max 20
   362→      if (pageToken) {
   363→        url.searchParams.set('pageToken', pageToken);
   364→      }
   365→
   366→      const response = await fetch(url.toString(), {
   367→        method: 'GET',
   368→        headers: {
   369→          'x-goog-api-key': apiKey,
   370→        },
   371→      });
   372→
   373→      if (!response.ok) {
   374→        const error = await response.json();
   375→        console.error('  ❌ ドキュメント一覧取得失敗:', error);
   376→        return allDocuments;
   377→      }
   378→
   379→      const data = await response.json();
   380→
   381→      if (data.documents) {
   382→        allDocuments.push(...data.documents);
   383→      }
   384→
   385→      pageToken = data.nextPageToken;
   386→    } while (pageToken);
   387→
   388→    return allDocuments;
   389→  } catch (error) {
   390→    console.error('  ❌ ドキュメント一覧取得失敗:', error);
   391→    return [];
   392→  }
   393→}
   394→
   395→// ========================================
   396→// 重複検出・削除関連の関数
   397→// ========================================
   398→
   399→/**
   400→ * URLに基づいてFile Search Store内の既存ドキュメントを検索
   401→ * customMetadataのurlフィールドで照合
   402→ *
   403→ * @returns 見つかったドキュメントのname（複数の場合は配列で返す）
   404→ */
   405→export async function findDocumentsByUrl(
   406→  apiKey: string,
   407→  fileSearchStoreName: string,
   408→  url: string
   409→): Promise<string[]> {
   410→  try {
   411→    const documents = await listFilesInStore(apiKey, fileSearchStoreName);
   412→    const matchingDocs: string[] = [];
   413→
   414→    for (const doc of documents) {
   415→      // customMetadataからurlを取得
   416→      const urlMeta = doc.customMetadata?.find(
   417→        (m: { key: string; stringValue?: string }) => m.key === 'url'
   418→      );
   419→
   420→      if (urlMeta?.stringValue === url) {
   421→        matchingDocs.push(doc.name);
   422→      }
   423→    }
   424→
   425→    if (matchingDocs.length > 0) {
   426→      console.log(`  🔍 URL "${url}" に一致するドキュメント: ${matchingDocs.length}件`);
   427→    }
   428→
   429→    return matchingDocs;
   430→  } catch (error) {
   431→    console.error('  ❌ ドキュメント検索失敗:', error);
   432→    return [];
   433→  }
   434→}
   435→
   436→/**
   437→ * displayNameに基づいてFile Search Store内の既存ドキュメントを検索
   438→ * チャンクファイル（_partXofY）も含めて検索
   439→ *
   440→ * @returns 見つかったドキュメントのname配列
   441→ */
   442→export async function findDocumentsByDisplayName(
   443→  apiKey: string,
   444→  fileSearchStoreName: string,
   445→  displayName: string
   446→): Promise<string[]> {
   447→  try {
   448→    const documents = await listFilesInStore(apiKey, fileSearchStoreName);
   449→    const matchingDocs: string[] = [];
   450→    const baseName = getBaseFileName(displayName);
   451→
   452→    for (const doc of documents) {
   453→      const docDisplayName = doc.displayName || '';
   454→      const docBaseName = getBaseFileName(docDisplayName);
   455→
   456→      // 完全一致またはチャンクファイルのベース名が一致
   457→      if (docDisplayName === displayName || docBaseName === baseName) {
   458→        matchingDocs.push(doc.name);
   459→      }
   460→    }
   461→
   462→    if (matchingDocs.length > 0) {
   463→      console.log(
   464→        `  🔍 displayName "${displayName}" に一致するドキュメント: ${matchingDocs.length}件`
   465→      );
   466→    }
   467→
   468→    return matchingDocs;
   469→  } catch (error) {
   470→    console.error('  ❌ ドキュメント検索失敗:', error);
   471→    return [];
   472→  }
   473→}
   474→
   475→/**
   476→ * URLに基づいて既存ドキュメントを削除（重複防止用）
   477→ * チャンクファイルも含めて削除
   478→ *
   479→ * @returns 削除したドキュメント数
   480→ */
   481→export async function deleteDocumentsByUrl(
   482→  apiKey: string,
   483→  fileSearchStoreName: string,
   484→  url: string
   485→): Promise<number> {
   486→  const documentNames = await findDocumentsByUrl(apiKey, fileSearchStoreName, url);
   487→
   488→  if (documentNames.length === 0) {
   489→    return 0;
   490→  }
   491→
   492→  console.log(`  🗑️ 重複ドキュメントを削除中: ${documentNames.length}件`);
   493→
   494→  let deletedCount = 0;
   495→  for (const docName of documentNames) {
   496→    const success = await deleteFromFileStore(apiKey, docName);
   497→    if (success) {
   498→      deletedCount++;
   499→    }
   500→  }
   501→
   502→  console.log(`  ✅ 削除完了: ${deletedCount}/${documentNames.length}件`);
   503→  return deletedCount;
   504→}
   505→
   506→/**
   507→ * displayNameに基づいて既存ドキュメントを削除（重複防止用）
   508→ * チャンクファイルも含めて削除
   509→ *
   510→ * @returns 削除したドキュメント数
   511→ */
   512→export async function deleteDocumentsByDisplayName(
   513→  apiKey: string,
   514→  fileSearchStoreName: string,
   515→  displayName: string
   516→): Promise<number> {
   517→  const documentNames = await findDocumentsByDisplayName(apiKey, fileSearchStoreName, displayName);
   518→
   519→  if (documentNames.length === 0) {
   520→    return 0;
   521→  }
   522→
   523→  console.log(`  🗑️ 重複ドキュメントを削除中: ${documentNames.length}件`);
   524→
   525→  let deletedCount = 0;
   526→  for (const docName of documentNames) {
   527→    const success = await deleteFromFileStore(apiKey, docName);
   528→    if (success) {
   529→      deletedCount++;
   530→    }
   531→  }
   532→
   533→  console.log(`  ✅ 削除完了: ${deletedCount}/${documentNames.length}件`);
   534→  return deletedCount;
   535→}
   536→
   537→// ========================================
   538→// チャンキング関連の定数と関数
   539→// ========================================
   540→
   541→/** チャンク分割のサイズ閾値（100KB以上で分割） */
   542→export const CHUNK_SIZE_THRESHOLD = 100 * 1024; // 100KB
   543→
   544→/** 1チャンクの最大サイズ */
   545→export const MAX_CHUNK_SIZE = 80 * 1024; // 80KB
   546→
   547→/** チャンクファイル名のパターン */
   548→export const CHUNK_PATTERN = /_part(\d+)of(\d+)$/;
   549→
   550→/**
   551→ * コンテンツサイズをKB単位で取得
   552→ */
   553→export function getContentSizeKB(content: string): number {
   554→  return Buffer.byteLength(content, 'utf-8') / 1024;
   555→}
   556→
   557→/**
   558→ * コンテンツがチャンキングを必要とするか判定
   559→ */
   560→export function shouldChunkContent(content: string): boolean {
   561→  return Buffer.byteLength(content, 'utf-8') > CHUNK_SIZE_THRESHOLD;
   562→}
   563→
   564→/**
   565→ * ファイル名がチャンク形式かどうか判定
   566→ */
   567→export function isChunkedFile(displayName: string): boolean {
   568→  return CHUNK_PATTERN.test(displayName);
   569→}
   570→
   571→/**
   572→ * チャンクファイル名からベース名を取得
   573→ */
   574→export function getBaseFileName(displayName: string): string {
   575→  return displayName.replace(CHUNK_PATTERN, '');
   576→}
   577→
   578→/**
   579→ * チャンクファイル名からパート情報を取得
   580→ */
   581→export function getChunkInfo(
   582→  displayName: string
   583→): { partNumber: number; totalParts: number } | null {
   584→  const match = displayName.match(CHUNK_PATTERN);
   585→  if (!match) return null;
   586→  return {
   587→    partNumber: parseInt(match[1], 10),
   588→    totalParts: parseInt(match[2], 10),
   589→  };
   590→}
   591→
   592→/**
   593→ * コンテンツをチャンクに分割
   594→ */
   595→export function splitContentIntoChunks(
   596→  content: string,
   597→  maxBytes: number = MAX_CHUNK_SIZE
   598→): string[] {
   599→  const chunks: string[] = [];
   600→  const lines = content.split('\n');
   601→  let currentChunk = '';
   602→
   603→  for (const line of lines) {
   604→    const testChunk = currentChunk ? `${currentChunk}\n${line}` : line;
   605→    if (Buffer.byteLength(testChunk, 'utf-8') > maxBytes && currentChunk) {
   606→      chunks.push(currentChunk);
   607→      currentChunk = line;
   608→    } else {
   609→      currentChunk = testChunk;
   610→    }
   611→  }
   612→
   613→  if (currentChunk) {
   614→    chunks.push(currentChunk);
   615→  }
   616→
   617→  return chunks;
   618→}
   619→
   620→export interface ChunkedUploadResult {
   621→  success: boolean;
   622→  chunked: boolean;
   623→  totalChunks: number;
   624→  successfulChunks: number;
   625→  results: UploadResult[];
   626→  error?: string;
   627→}
   628→
   629→/**
   630→ * 大きなファイルを分割してアップロード
   631→ */
   632→export async function uploadToFileStoreWithChunking(
   633→  apiKey: string,
   634→  content: string,
   635→  metadata: FileMetadata
   636→): Promise<ChunkedUploadResult> {
   637→  const needsChunking = shouldChunkContent(content);
   638→
   639→  if (!needsChunking) {
   640→    // チャンキング不要の場合は通常アップロード
   641→    const result = await uploadToFileStore(apiKey, content, metadata);
   642→    return {
   643→      success: result.success,
   644→      chunked: false,
   645→      totalChunks: 1,
   646→      successfulChunks: result.success ? 1 : 0,
   647→      results: [result],
   648→      error: result.error,
   649→    };
   650→  }
   651→
   652→  // チャンクに分割
   653→  const chunks = splitContentIntoChunks(content);
   654→  const totalChunks = chunks.length;
   655→  const results: UploadResult[] = [];
   656→
   657→  console.log(`  📦 ファイルを${totalChunks}個のチャンクに分割してアップロード`);
   658→
   659→  for (let i = 0; i < chunks.length; i++) {
   660→    const chunkMetadata: FileMetadata = {
   661→      ...metadata,
   662→      display_name: `${metadata.display_name}_part${i + 1}of${totalChunks}`,
   663→    };
   664→
   665→    console.log(`  📤 チャンク ${i + 1}/${totalChunks} をアップロード中...`);
   666→    const result = await uploadToFileStore(apiKey, chunks[i], chunkMetadata);
   667→    results.push(result);
   668→
   669→    // レート制限対策: チャンク間に少し待機
   670→    if (i < chunks.length - 1) {
   671→      await new Promise(resolve => setTimeout(resolve, 1000));
   672→    }
   673→  }
   674→
   675→  const successfulChunks = results.filter(r => r.success).length;
   676→
   677→  return {
   678→    success: successfulChunks === totalChunks,
   679→    chunked: true,
   680→    totalChunks,
   681→    successfulChunks,
   682→    results,
   683→    error:
   684→      successfulChunks < totalChunks
   685→        ? `${totalChunks - successfulChunks}個のチャンクがアップロードに失敗しました`
   686→        : undefined,
   687→  };
   688→}
