import 'server-only';
import { NextRequest, NextResponse } from 'next/server';
import {
  uploadToFileStore,
  updateManifest,
  deleteDocumentsByDisplayName,
  type ManifestFile,
} from '@/../scripts/data-upload/lib/file-uploader';
import path from 'path';
import fs from 'fs';
import type { AdminApiResponse } from '@/types/admin';

/**
 * Route Segment Config
 * ファイルアップロード用の設定
 */
export const dynamic = 'force-dynamic';
export const maxDuration = 60; // タイムアウトを60秒に設定

/**
 * Vercel環境かどうかを判定
 */
const isVercel = process.env.VERCEL === '1';

/**
 * 環境に応じたmanifestファイルパスを取得
 */
function getManifestPath(): string {
  const storeName = process.env.FILE_SEARCH_STORE_NAME || '';
  const isStaging = storeName.includes('staging');
  const fileName = isStaging ? 'file-store-manifest-staging.json' : 'file-store-manifest.json';
  return path.join(process.cwd(), 'data', fileName);
}

/**
 * manifestのステータスを更新
 * Vercel環境ではファイルシステムへの書き込みができないためスキップ
 */
function updateManifestStatus(
  fileId: string,
  status: 'uploading' | 'completed' | 'failed',
  errorMessage?: string,
  actualFileId?: string
): void {
  // Vercel環境ではファイル書き込み不可
  if (isVercel) {
    console.log(`[Vercel] Manifest update skipped: ${fileId} -> ${status}`);
    return;
  }

  try {
    const manifestPath = getManifestPath();
    if (!fs.existsSync(manifestPath)) return;

    const manifest = JSON.parse(fs.readFileSync(manifestPath, 'utf-8'));
    const fileIndex = manifest.files.findIndex((f: any) => f.file_id === fileId);

    if (fileIndex !== -1) {
      manifest.files[fileIndex].status = status;
      if (errorMessage) {
        manifest.files[fileIndex].error_message = errorMessage;
      }
      if (actualFileId && status === 'completed') {
        manifest.files[fileIndex].file_id = actualFileId;
      }
      manifest.updated_at = new Date().toISOString();
      fs.writeFileSync(manifestPath, JSON.stringify(manifest, null, 2));
    }
  } catch (error) {
    console.error('Manifest update failed:', error);
  }
}

const MAX_FILE_SIZE = 4.5 * 1024 * 1024; // 4.5MB (Vercelの制限)

const ALLOWED_EXTENSIONS = ['.txt', '.md', '.json', '.csv', '.xlsx', '.xls', '.pdf'];

/**
 * バックグラウンドでアップロード処理を実行
 *
 * 重複防止: Store Documents APIで同名ドキュメントを検索・削除してからアップロード
 */
async function processUploadInBackground(
  apiKey: string,
  content: string,
  displayName: string,
  sourceType: 'qa' | 'web',
  locale: string,
  finalCategory: string,
  tempFileId: string
): Promise<void> {
  try {
    console.log(`📤 バックグラウンドアップロード開始: ${displayName}`);

    // Store Documents APIで同名ドキュメントを検索・削除（重複防止）
    const fileSearchStoreName = process.env.FILE_SEARCH_STORE_NAME;
    if (fileSearchStoreName) {
      console.log(`🔍 同名ドキュメントを検索中: ${displayName}`);
      const deletedCount = await deleteDocumentsByDisplayName(
        apiKey,
        fileSearchStoreName,
        displayName
      );
      if (deletedCount > 0) {
        console.log(`🗑️ 既存ドキュメントを削除しました: ${deletedCount}件`);
      }
    }

    const uploadResult = await uploadToFileStore(apiKey, content, {
      display_name: displayName,
      source_type: sourceType,
      locale: locale,
      category: finalCategory,
    });

    if (!uploadResult.success) {
      console.error(`❌ アップロード失敗: ${uploadResult.error}`);
      updateManifestStatus(
        tempFileId,
        'failed',
        uploadResult.error || 'アップロードに失敗しました'
      );
      return;
    }

    // 成功時: ステータスを更新し、実際のfile_idに置き換え
    updateManifestStatus(tempFileId, 'completed', undefined, uploadResult.file_id);
    console.log(`✅ バックグラウンドアップロード完了: ${uploadResult.file_id}`);
  } catch (error) {
    console.error('❌ バックグラウンドアップロードエラー:', error);
    updateManifestStatus(
      tempFileId,
      'failed',
      error instanceof Error ? error.message : '予期しないエラーが発生しました'
    );
  }
}

/**
 * ファイルアップロードAPI
 * POST /api/admin/upload
 *
 * 非同期処理: 即座にレスポンスを返し、バックグラウンドでアップロード
 */
export async function POST(request: NextRequest) {
  try {
    // FormDataからファイルとメタデータを取得
    const formData = await request.formData();
    const file = formData.get('file') as File | null;
    const category = (formData.get('category') as string) || undefined;
    const locale = (formData.get('locale') as string) || 'ja';
    const sourceType = (formData.get('source_type') as 'qa' | 'web') || 'qa';

    // バリデーション
    if (!file) {
      return NextResponse.json<AdminApiResponse>(
        { success: false, error: 'ファイルが選択されていません' },
        { status: 400 }
      );
    }

    // ファイルサイズチェック
    if (file.size > MAX_FILE_SIZE) {
      return NextResponse.json<AdminApiResponse>(
        { success: false, error: 'ファイルサイズが大きすぎます（上限: 4.5MB）' },
        { status: 400 }
      );
    }

    // ファイル拡張子チェック
    const ext = path.extname(file.name).toLowerCase();
    if (!ALLOWED_EXTENSIONS.includes(ext)) {
      return NextResponse.json<AdminApiResponse>(
        {
          success: false,
          error: `対応していないファイル形式です。対応形式: ${ALLOWED_EXTENSIONS.join(', ')}`,
        },
        { status: 400 }
      );
    }

    // Gemini API キーチェック
    const apiKey = process.env.GEMINI_API_KEY;
    if (!apiKey) {
      console.error('❌ GEMINI_API_KEY環境変数が設定されていません');
      return NextResponse.json<AdminApiResponse>(
        { success: false, error: 'サーバー設定エラー' },
        { status: 500 }
      );
    }

    // ファイル内容を読み込む
    const arrayBuffer = await file.arrayBuffer();
    let content: string;

    // Excelファイルの場合は変換処理
    if (['.xlsx', '.xls'].includes(ext)) {
      const xlsx = await import('xlsx');
      const workbook = xlsx.read(arrayBuffer);
      content = '';

      // 全シートをテキストに変換
      for (const sheetName of workbook.SheetNames) {
        const sheet = workbook.Sheets[sheetName];
        content += `## ${sheetName}\n\n`;
        content += xlsx.utils.sheet_to_csv(sheet);
        content += '\n\n';
      }
    } else {
      // テキストファイルとして読み込み
      const decoder = new TextDecoder('utf-8');
      content = decoder.decode(arrayBuffer);
    }

    // display_nameを生成（プレフィックスなし、元のファイル名をそのまま使用）
    const displayName = file.name;
    const finalCategory = category || path.basename(file.name, ext);

    // 一時的なfile_idを生成（アップロード中の識別用）
    const tempFileId = `uploading-${Date.now()}`;

    // Vercel環境では同期的にアップロード（バックグラウンド処理は関数終了で中断されるため）
    if (isVercel) {
      console.log(`[Vercel] 同期アップロード開始: ${displayName}`);

      // Store Documents APIで同名ドキュメントを検索・削除（重複防止）
      const fileSearchStoreName = process.env.FILE_SEARCH_STORE_NAME;
      if (fileSearchStoreName) {
        console.log(`🔍 同名ドキュメントを検索中: ${displayName}`);
        const deletedCount = await deleteDocumentsByDisplayName(
          apiKey,
          fileSearchStoreName,
          displayName
        );
        if (deletedCount > 0) {
          console.log(`🗑️ 既存ドキュメントを削除しました: ${deletedCount}件`);
        }
      }

      const uploadResult = await uploadToFileStore(apiKey, content, {
        display_name: displayName,
        source_type: sourceType,
        locale: locale,
        category: finalCategory,
      });

      if (!uploadResult.success) {
        console.error(`❌ アップロード失敗: ${uploadResult.error}`);
        return NextResponse.json<AdminApiResponse>(
          { success: false, error: uploadResult.error || 'アップロードに失敗しました' },
          { status: 500 }
        );
      }

      console.log(`✅ アップロード完了: ${uploadResult.file_id}`);
      return NextResponse.json<AdminApiResponse>({
        success: true,
        data: {
          file_id: uploadResult.file_id,
          display_name: displayName,
          category: finalCategory,
          locale: locale,
          source_type: sourceType,
          status: 'completed',
        },
      });
    }

    // ローカル環境: Manifest に "uploading" ステータスで登録してバックグラウンド処理
    const manifestFile: ManifestFile = {
      file_id: tempFileId,
      display_name: displayName,
      source_type: sourceType,
      uploaded_at: new Date().toISOString(),
      locale: locale,
      category: finalCategory,
    };

    try {
      const manifestPath = getManifestPath();
      let manifest: any;
      if (fs.existsSync(manifestPath)) {
        manifest = JSON.parse(fs.readFileSync(manifestPath, 'utf-8'));
      } else {
        manifest = { version: '3.0.0', updated_at: '', files: [] };
      }

      manifest.files.push({
        ...manifestFile,
        status: 'uploading',
      });
      manifest.updated_at = new Date().toISOString();
      fs.writeFileSync(manifestPath, JSON.stringify(manifest, null, 2));
    } catch (error) {
      console.error('Manifest write failed:', error);
    }

    // バックグラウンドでアップロード処理を開始（awaitしない）
    processUploadInBackground(
      apiKey,
      content,
      displayName,
      sourceType,
      locale,
      finalCategory,
      tempFileId
    ).catch(err => {
      console.error('バックグラウンド処理の未処理エラー:', err);
    });

    // 即座にレスポンスを返す
    return NextResponse.json<AdminApiResponse>({
      success: true,
      data: {
        file_id: tempFileId,
        display_name: displayName,
        category: finalCategory,
        locale: locale,
        source_type: sourceType,
        status: 'uploading',
      },
    });
  } catch (error) {
    console.error('❌ アップロードエラー:', error);
    return NextResponse.json<AdminApiResponse>(
      {
        success: false,
        error: error instanceof Error ? error.message : '予期しないエラーが発生しました',
      },
      { status: 500 }
    );
  }
}

