 * GET /api/admin/files
 *
 * 常にFile Search Store APIから直接データを取得（自動同期）
 * source_type: 'qa' のファイルのみを返す
 */
export async function GET(): Promise<NextResponse<AdminApiResponse<FilesResponseData>>> {
  try {
    const apiKey = process.env.GEMINI_API_KEY;
    if (!apiKey) {
      return NextResponse.json(
        { success: false, error: 'GEMINI_API_KEY not configured' },
        { status: 500 }
      );
    }

    const storeName = process.env.FILE_SEARCH_STORE_NAME;
    if (!storeName) {
      return NextResponse.json(
        { success: false, error: 'FILE_SEARCH_STORE_NAME not configured' },
        { status: 500 }
      );
    }

    console.log(`[Admin Files API] Fetching from File Search Store: ${storeName}`);

    // File Search Store APIからドキュメント一覧を取得
    const documents = await fetchDocumentsFromStore(apiKey, storeName);
    console.log(`[Admin Files API] Fetched ${documents.length} documents`);

    // ドキュメントをファイル情報に変換し、QAファイルのみをフィルタ
    // 注: STATE_ACTIVE以外のファイル（処理中など）も表示する
    const qaFiles = documents
      .filter(doc => {
        const sourceType = getMetadata(doc, 'source_type');
        return sourceType === 'qa';
      })
      .map(doc => {
        // ドキュメントの状態をステータスにマッピング
        let status: 'completed' | 'uploading' | 'failed' = 'uploading';
        if (doc.state === 'STATE_ACTIVE') {
          status = 'completed';
        } else if (doc.state === 'STATE_FAILED') {
          status = 'failed';
        }

        return {
          file_id: doc.name,
          display_name: doc.displayName || doc.name,
          source_type: 'qa' as const,
          uploaded_at: doc.createTime,

